// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const all = $input.all();
const inputs = $('Parse & Validate Inputs').item.json;

let serpResults = [];
let googleTrendsData = null;
let mapsData = [];
let absRawData = null;

for (const item of all) {
  const j = item.json;
  if (!j) continue;
  if (j?.data?.dataSets || j?.structure?.dimensions) { absRawData = j; continue; }
  if (j?.results && Array.isArray(j.results) && j.results[0]?.place_id !== undefined) { mapsData = j.results; continue; }
  if (j?.interest_over_time) { googleTrendsData = j.interest_over_time; continue; }
  if (j?.organic_results && Array.isArray(j.organic_results)) {
    serpResults = serpResults.concat(j.organic_results);
  }
}

const seenTitles = new Set();
const allArticles = serpResults.filter(r => {
  const t = (r.title || '').toLowerCase().trim();
  if (seenTitles.has(t)) return false;
  seenTitles.add(t);
  return true;
}).slice(0, 12);

let absRetailData = null;
let absRetailTrend = 'Unknown';
let absRetailLabel = 'ABS data unavailable';
let absDataSource  = 'Not fetched';
let absMomChange   = null;
let absYoyChange   = null;

if (absRawData) {
  try {
    const datasets = absRawData?.data?.dataSets || [];
    const seriesObj = datasets?.[0]?.series || {};
    const seriesKeys = Object.keys(seriesObj);
    if (seriesKeys.length > 0) {
      const obs = seriesObj[seriesKeys[0]]?.observations || {};
      const values = Object.entries(obs)
        .sort((a,b) => parseInt(a[0]) - parseInt(b[0]))
        .map(([,v]) => parseFloat(Array.isArray(v) ? v[0] : v))
        .filter(v => !isNaN(v) && v > 0);
      if (values.length >= 2) {
        const latest  = values[values.length - 1];
        const prev    = values[values.length - 2];
        const yoyBase = values.length >= 5 ? values[values.length - 5] : null;
        absMomChange  = parseFloat(((latest - prev) / prev * 100).toFixed(1));
        absYoyChange  = yoyBase ? parseFloat(((latest - yoyBase) / yoyBase * 100).toFixed(1)) : null;
        absRetailData = { latest_value: Math.round(latest), prev_value: Math.round(prev), mom_change_pct: absMomChange, yoy_change_pct: absYoyChange, series_points: values.length, series_key: inputs.abs_series_key, unit: 'A$m (seasonally adjusted turnover)' };
        absRetailTrend = absYoyChange === null ? 'Unknown' : absYoyChange > 5 ? 'Strong Growth' : absYoyChange > 2 ? 'Moderate Growth' : absYoyChange > 0 ? 'Slight Growth' : absYoyChange > -2 ? 'Flat' : absYoyChange > -5 ? 'Slight Decline' : 'Declining';
        const qStr = absMomChange > 0 ? `+${absMomChange}%` : `${absMomChange}%`;
        const yoyStr = absYoyChange !== null ? (absYoyChange > 0 ? `+${absYoyChange}%` : `${absYoyChange}%`) + ' YoY' : 'YoY N/A';
        absRetailLabel = `ABS Retail Trade RT (live, seasonally adjusted): ${qStr} QoQ, ${yoyStr} — Trend: ${absRetailTrend}`;
        absDataSource  = `ABS Retail Trade API — Series ${inputs.abs_series_key} — Cafes, Restaurants & Takeaway (ANZSIC 451+452, Australia, SA)`;
      } else {
        absRetailLabel = `ABS API responded but insufficient data points (${values.length} found, need 2+)`;
        absDataSource  = 'ABS RT API — partial data';
      }
    } else {
      absRetailLabel = 'ABS RT API returned empty series object — series key may be invalid';
      absDataSource  = 'ABS RT API — empty';
    }
  } catch(e) {
    absRetailLabel = 'ABS parse error: ' + e.message;
    absDataSource  = 'ABS RT API — parse error';
  }
}

let a1 = {};
try { a1 = (JSON.parse(inputs.a1_competitor_data || '{}')).outputs || {}; } catch(e) {}
let a2 = {};
try { a2 = (JSON.parse(inputs.a2_rent_data || '{}')).outputs || {}; } catch(e) {}
let targetSegments = [];
try { targetSegments = JSON.parse(inputs.target_customer_segments || '[]'); } catch(e) {}

const competitorBusinesses = mapsData.slice(0, 15).map(p => ({ name: p.name, type: (p.types || []).slice(0, 3).join(', '), rating: p.rating ?? 'N/A', reviews: p.user_ratings_total ?? 0, address: p.formatted_address, place_id: p.place_id }));
const totalCompetitors = competitorBusinesses.length;
const ratedCompetitors = competitorBusinesses.filter(b => typeof b.rating === 'number');
const avgRating = ratedCompetitors.length > 0 ? (ratedCompetitors.reduce((s,b) => s + b.rating, 0) / ratedCompetitors.length).toFixed(1) : 'N/A';
const totalReviews = competitorBusinesses.reduce((s,b) => s + (b.reviews || 0), 0);
const highRatedCount = ratedCompetitors.filter(b => b.rating >= 4.4).length;

let trendDirection = 'Unknown', trendAvgRecent = null, trendAvgOld = null;
if (googleTrendsData?.timeline_data) {
  const values = googleTrendsData.timeline_data.map(t => t.values?.[0]?.extracted_value || 0).filter(v => v > 0);
  if (values.length >= 4) {
    const mid = Math.floor(values.length / 2);
    trendAvgOld    = Math.round(values.slice(0, mid).reduce((a,b) => a+b,0) / mid);
    trendAvgRecent = Math.round(values.slice(mid).reduce((a,b) => a+b,0) / (values.length - mid));
    trendDirection = trendAvgRecent > trendAvgOld * 1.1 ? 'Rising' : trendAvgRecent < trendAvgOld * 0.9 ? 'Falling' : 'Stable';
  }
}

const articleSummaries = allArticles.slice(0, 10).map(r => ({ title: r.title || '', snippet: (r.snippet || '').slice(0, 200), source: r.displayed_link || '', link: r.link || '' }));
const articleText = articleSummaries.length > 0 ? articleSummaries.map((a,i) => `${i+1}. ${a.title}\n   ${a.snippet}\n   Source: ${a.source}`).join('\n\n') : 'No articles found.';
const trendsContext = googleTrendsData ? `Google Trends (12m, ${inputs.country}): Direction=${trendDirection}, Recent avg=${trendAvgRecent}, Older avg=${trendAvgOld}` : 'Google Trends: No data returned';
const mapsContext = `${totalCompetitors} similar businesses found within 1km.\nAvg rating: ${avgRating}. Total reviews: ${totalReviews}. High-rated (≥4.4): ${highRatedCount}.\n` + competitorBusinesses.slice(0, 10).map((b,i) => `${i+1}. ${b.name} (${b.type}) — Rating: ${b.rating}, Reviews: ${b.reviews}`).join('\n');
const a1Context = Object.keys(a1).length > 0 ? `Density Score: ${a1.competitor_density_score||'N/A'} | Saturation: ${a1.saturation_level||'N/A'}\nOpportunity Gaps: ${(a1.opportunity_gaps||[]).join('; ')}\nWithin 500m: ${a1.competitors_within_500m??'N/A'} competitors\nLocality: ${a1.locality_context||'N/A'}` : 'No A1 competitor data provided.';
const a2Context = Object.keys(a2).length > 0 ? `Rent Feasibility: ${a2.rent_feasibility_score||'N/A'}/100 | Range: ${a2.rent_range_actual?.min}–${a2.rent_range_actual?.max}\nAnchor Businesses: ${(a2.anchor_businesses_nearby||[]).map(b=>b.name).join(', ')}\nTransport: ${a2.transport_access_score||'N/A'}/10 | Verdict: ${a2.overall_location_verdict||'N/A'}` : 'No A2 rent data provided.';

return [{ json: { business_type: inputs.business_type, industry_category: inputs.industry_category, city: inputs.city, area: inputs.area, locality: inputs.locality, country: inputs.country, business_stage: inputs.business_stage, target_customer_segments: targetSegments, email: inputs.email, abs_retail_data: absRetailData, abs_retail_trend: absRetailTrend, abs_retail_label: absRetailLabel, abs_data_source: absDataSource, abs_mom_change: absMomChange, abs_yoy_change: absYoyChange, competitor_businesses: competitorBusinesses, total_competitors_1km: totalCompetitors, avg_competitor_rating: avgRating, high_rated_count: highRatedCount, total_reviews: totalReviews, trends_direction: trendDirection, trends_recent_avg: trendAvgRecent, trends_older_avg: trendAvgOld, article_summaries: articleSummaries, article_text: articleText, trends_context: trendsContext, maps_context: mapsContext, a1_context: a1Context, a2_context: a2Context, segments_text: targetSegments.length > 0 ? targetSegments.join(', ') : 'General consumers', data_sources: { news_articles: serpResults.filter(r => !r.organic_results).length, total_articles_deduped: allArticles.length, google_trends: googleTrendsData ? 'Available' : 'Unavailable', maps_competitors: totalCompetitors, abs_retail_trade: absDataSource } }}];

const inputJson = $input.first().json;
const rawText = inputJson.output || inputJson.text || inputJson.response || JSON.stringify(inputJson);
let analysis;
try {
  let cleaned = rawText.trim().replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  const start = cleaned.indexOf('{'), end = cleaned.lastIndexOf('}');
  if (start !== -1 && end > start) cleaned = cleaned.slice(start, end + 1);
  cleaned = cleaned.replace(/(:\s*)(\d{1,3}(?:,\d{3})+)([,\}\]\s\n])/g,(m,pre,num,post)=>pre+num.replace(/,/g,'')+post);
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error: true, raw_response: rawText.slice(0,800), error_message: e.message };
}
const d = $('Process & Merge All Data').item.json;
return [{ json: { agent_id: 'A3', agent_name: 'Market Growth & Demand (ABS Live)', status: analysis.parse_error ? 'error' : 'success', timestamp: new Date().toISOString(), email: d.email, inputs_used: { location: `${d.locality}, ${d.area}, ${d.city}`, industry: d.industry_category, business_stage: d.business_stage, segments: d.target_customer_segments }, competitor_businesses: d.competitor_businesses, data_sources: { ...d.data_sources, abs_yoy_change: d.abs_yoy_change, abs_mom_change: d.abs_mom_change }, outputs: { growth_score: analysis.growth_score ?? null, market_maturity_stage: analysis.market_maturity_stage || null, demand_trend: analysis.demand_trend || null, demand_trend_reasoning: analysis.demand_trend_reasoning || null, abs_data_summary: analysis.abs_data_summary || { source: d.abs_data_source, mom_change_pct: d.abs_mom_change, yoy_change_pct: d.abs_yoy_change, trend: d.abs_retail_trend }, five_year_forecast: analysis.five_year_forecast || null, seasonal_demand_patterns: analysis.seasonal_demand_patterns || [], target_customer_segments: analysis.target_customer_segments || [], competitor_threat_level: analysis.competitor_threat_level || null, competitor_threat_reasoning: analysis.competitor_threat_reasoning || null, regulatory_flags: analysis.regulatory_flags || [], market_entry_window: analysis.market_entry_window || null, best_entry_timing: analysis.best_entry_timing || null, entry_timing_reasoning: analysis.entry_timing_reasoning || null, opportunity_score: analysis.opportunity_score ?? null, top_opportunities: analysis.top_opportunities || [], top_risks: analysis.top_risks || [], overall_market_verdict: analysis.overall_market_verdict || null, agent_notes: analysis.agent_notes || null } }}];

// ── Output validation ──
const required_keys = Object.keys(analysis).filter(k => !k.startsWith('_') && !k.startsWith('raw'));
if (required_keys.length < 3 || analysis.parse_error) {
  analysis._validation_failed = true;
  analysis._validation_reason = analysis.parse_error ? 'JSON parse error' : 'Insufficient output fields (' + required_keys.length + ')';
}
analysis._validated_at = new Date().toISOString();
analysis._agent_version = 'v2';
